                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(LiveVolResponseMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != LiveVolResponseMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(LiveVolResponseMessage.BlockLength);
            builder.Append("):");

            builder.Append("RequestId=");
            builder.Append(this.RequestId);
            builder.Append('|');
            builder.Append("Count=");
            builder.Append(this.Count);
            builder.Append('|');
            builder.Append("LiveVolData=[");
            var liveVolData = this.LiveVolData;
            if (liveVolData.Count > 0)
            {
                var first = true;
                while (liveVolData.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    liveVolData.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
    }
}
